// ═══════════════════════════════════════════════════════════
// ⚙️  CONFIGURATION — Remplir avant utilisation
// ═══════════════════════════════════════════════════════════
const ANTHROPIC_API_KEY    = 'REMPLACER_PAR_CLE_ANTHROPIC';
const BREVO_API_KEY        = 'REMPLACER_PAR_CLE_BREVO';
const LEADFLOW_BASE_URL    = 'https://REMPLACER.railway.app'; // URL Railway
const AGENCE_NOM           = 'Votre Agence';
const AGENCE_EMAIL         = 'contact@agence.fr'; // adresse d'envoi Brevo
// ═══════════════════════════════════════════════════════════

const email = $input.first().json;

// Extrait l'expéditeur
const fromAddr = email.from?.value?.[0]?.address || email.from?.text || '';
const fromName = email.from?.value?.[0]?.name || fromAddr;

// Filtre les emails sortants (évite boucles)
if (fromAddr.toLowerCase().includes(AGENCE_EMAIL.toLowerCase())) {
  return [];
}

// Corps texte
const body = email.text
  || (email.html || '').replace(/<[^>]+>/g, ' ').replace(/\s{2,}/g, ' ').trim();

return [{
  json: {
    from:            fromAddr,
    from_name:       fromName,
    subject:         email.subject || '',
    body:            body.substring(0, 4000),
    _anthropic_key:  ANTHROPIC_API_KEY,
    _brevo_key:      BREVO_API_KEY,
    _leadflow_url:   LEADFLOW_BASE_URL,
    _agence_nom:     AGENCE_NOM,
    _agence_email:   AGENCE_EMAIL,
  }
}];

