const input     = $input.first().json;
const raw       = input.content?.[0]?.text || '';

let parsed = { complexite: 'complexe', raison: 'Analyse impossible', sujet_reponse: 'Re: ' + input._subject, reponse: '' };
try {
  const match = raw.match(/\{[\s\S]*\}/);
  if (match) parsed = JSON.parse(match[0]);
} catch(e) {}

// Récupère les champs passés en amont via le nœud config
const prev = $('⚙️ Config + Préparer Email').first().json;

return [{
  json: {
    from:            prev.from,
    subject:         prev.subject,
    body:            prev.body,
    complexite:      parsed.complexite || 'complexe',
    raison:          parsed.raison     || '',
    sujet_reponse:   parsed.sujet_reponse || ('Re: ' + prev.subject),
    reponse:         parsed.reponse    || '',
    _brevo_key:      prev._brevo_key,
    _leadflow_url:   prev._leadflow_url,
    _agence_nom:     prev._agence_nom,
    _agence_email:   prev._agence_email,
  }
}];

